// --- types.d.ts ---
/**
 * Weather Card Component - Type Definitions
 * All shared interfaces for the component and sub-components
 */

// Main Props interface matching the data contract
export interface Props {
  /** City name */
  city: string;
  /** Current temperature value */
  temperature: number;
  /** Weather condition (e.g., "Sunny", "Cloudy", "Rainy") */
  condition: string;
  /** Humidity percentage (0-100) */
  humidity: number;
  /** Wind speed value */
  windSpeed: number;
  /** Temperature unit (default: "C") */
  unit?: string;
  /** Array of 5-day forecast data */
  forecast: ForecastDay[];
}

// Forecast day structure from data contract
export interface ForecastDay {
  /** Day abbreviation (e.g., "Mon", "Tue") */
  day: string;
  /** Weather icon/emoji (e.g., "☀️", "⛅", "🌧️") */
  icon: string;
  /** High temperature */
  high: number;
  /** Low temperature */
  low: number;
}

// Hook return type for weather card logic
export interface HookReturn {
  /** Formatted temperature string with unit */
  temperatureDisplay: string;
  /** Condition category for consistent iconography mapping */
  conditionCategory: ConditionCategory;
  /** Formatted humidity display string */
  humidityDisplay: string;
  /** Formatted wind speed display string */
  windSpeedDisplay: string;
  /** Processed forecast for rendering */
  processedForecast: ProcessedForecastDay[];
}

// Condition types for icon/styling mapping
export type ConditionCategory = "sunny" | "cloudy" | "rainy" | "snowy" | "stormy" | "foggy" | "unknown";

// Processed forecast structure for UI consumption
export interface ProcessedForecastDay extends ForecastDay {
  /** CSS class or category for styling */
  styleCategory: ConditionCategory;
}

// Props for CurrentWeather sub-component
export interface CurrentWeatherProps {
  /** City name to display */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Temperature unit */
  unit: string;
  /** Weather condition text */
  condition: string;
  /** Condition category for icon/styling */
  conditionCategory: ConditionCategory;
}

// Props for WeatherDetails sub-component
export interface WeatherDetailsProps {
  /** Humidity percentage */
  humidity: number;
  /** Wind speed value */
  windSpeed: number;
  /** Temperature unit for context */
  unit: string;
}

// Props for ForecastStrip sub-component
export interface ForecastStripProps {
  /** Array of forecast days to display */
  forecast: ProcessedForecastDay[];
  /** Temperature unit for display */
  unit: string;
}

// Props for ForecastCard sub-component (individual forecast item)
export interface ForecastCardProps {
  /** Day abbreviation */
  day: string;
  /** Weather icon/emoji */
  icon: string;
  /** High temperature */
  high: number;
  /** Low temperature */
  low: number;
  /** Temperature unit */
  unit: string;
  /** Condition category for styling */
  styleCategory: ConditionCategory;
}


