/**
 * Weather Card Constants
 * Contains weather condition mappings, icon associations, and design tokens
 * for consistent rendering across all weather card components.
 */

import type { ConditionCategory } from './types';

/**
 * Maps weather condition strings to their standardized category types.
 * Handles common weather API variations and aliases for case-insensitive matching.
 * Unknown conditions default to "unknown" category.
 */
export const CONDITION_CATEGORY_MAP: Record<string, ConditionCategory> = {
  // Sunny/Clear conditions
  sunny: 'sunny',
  clear: 'sunny',
  'clear sky': 'sunny',
  'blue sky': 'sunny',

  // Cloudy conditions
  cloudy: 'cloudy',
  overcast: 'cloudy',
  'partly cloudy': 'cloudy',
  'mostly cloudy': 'cloudy',
  haze: 'cloudy',

  // Rainy conditions
  rainy: 'rainy',
  rain: 'rainy',
  drizzle: 'rainy',
  'light rain': 'rainy',
  'moderate rain': 'rainy',
  'heavy rain': 'rainy',
  'light drizzle': 'rainy',

  // Snowy conditions
  snowy: 'snowy',
  snow: 'snowy',
  'light snow': 'snowy',
  'moderate snow': 'snowy',
  'heavy snow': 'snowy',

  // Stormy conditions
  stormy: 'stormy',
  thunderstorm: 'stormy',
  'thunder storm': 'stormy',
  'severe thunderstorm': 'stormy',
  'with thunder': 'stormy',

  // Foggy conditions
  foggy: 'foggy',
  fog: 'foggy',
  mist: 'foggy',
  'light fog': 'foggy',
  'dense fog': 'foggy',
};

/**
 * Maps condition categories to their corresponding weather emoji icons.
 * Provides visual representation for each weather condition type.
 */
export const CONDITION_ICON_MAP: Record<ConditionCategory, string> = {
  sunny: '☀️',
  cloudy: '⛅',
  rainy: '🌧️',
  snowy: '❄️',
  stormy: '⛈️',
  foggy: '🌫️',
  unknown: '❓',
};

/**
 * Design system CSS variable tokens for colors, spacing, typography, and other properties.
 * Provides centralized references to all CSS custom properties used throughout the component.
 */
export const DESIGN_TOKENS = {
  colors: {
    primary: 'var(--ggui-color-primary)',
    secondary: 'var(--ggui-color-secondary)',
    text: {
      primary: 'var(--ggui-text-primary)',
      secondary: 'var(--ggui-text-secondary)',
      muted: 'var(--ggui-text-muted)',
    },
    background: {
      main: 'var(--ggui-bg-main)',
      card: 'var(--ggui-bg-card)',
      accent: 'var(--ggui-bg-accent)',
    },
