// hooks.ts
import { Props, HookReturn, ConditionCategory, ProcessedForecastDay } from './types';

/**
 * Helper function to categorize weather conditions into predefined categories
 * Maps condition strings to ConditionCategory enum using keyword matching
 */
const categorizeCondition = (condition: string): ConditionCategory => {
  if (!condition) {
    return 'unknown';
  }

  const normalizedCondition = condition.toLowerCase().trim();

  if (normalizedCondition.includes('sunny') || normalizedCondition.includes('clear')) {
    return 'sunny';
  }
  if (normalizedCondition.includes('cloud')) {
    return 'cloudy';
  }
  if (normalizedCondition.includes('rain')) {
    return 'rainy';
  }
  if (normalizedCondition.includes('snow')) {
    return 'snowy';
  }
  if (normalizedCondition.includes('storm') || normalizedCondition.includes('thunder')) {
    return 'stormy';
  }
  if (normalizedCondition.includes('fog') || normalizedCondition.includes('mist')) {
    return 'foggy';
  }

  return 'unknown';
};

/**
 * Helper function to map weather emoji icons to condition categories
 * Used for forecast processing when condition strings are not available
 */
const emojiToCondition = (icon: string): ConditionCategory => {
  if (!icon) {
    return 'unknown';
  }

  const emojiMap: Record<string, ConditionCategory> = {
    '☀️': 'sunny',
    '🌞': 'sunny',
    '⛅': 'cloudy',
    '🌤️': 'cloudy',
    '☁️': 'cloudy',
    '🌧️': 'rainy',
    '🌦️': 'rainy',
    '⛈️': 'stormy',
    '🌩️': 'stormy',
    '❄️': 'snowy',
    '⛄': 'snowy',
    '🌨️': 'snowy',
    '🌫️': 'foggy',
    '🌊': 'rainy',
  };

  return emojiMap[icon] || 'unknown';
};

/**
 * Helper function to format temperature with unit
 * Returns a string in the format "{temperature}°{unit}"
 */
const formatTemperature = (temp: number, unit: string): string => {
  const roundedTemp = Math.round(temp);
  return `${roundedTemp}°${unit}`;
};

/**
 * Custom React hook for processing weather card data
 * Handles temperature formatting, condition categorization, and forecast processing
 */
export const useComponent = (props: Props): HookReturn => {
  // Default unit to "C" if not provided
  const unit = props.unit || 'C';

  // 1. Format temperature display
  const temperatureDisplay = formatTemperature(props.temperature, unit);

  // 2. Categorize current weather condition
  const conditionCategory = categorizeCondition(props.condition);

  // 3. Format humidity display
  const clampedHumidity = Math.min(Math.max(props.humidity, 0), 100);
  const humidityDisplay = `${clampedHumidity}%`;

  // 4. Format wind speed display (rounded to 1 decimal place)
  const roundedWindSpeed = Math.round(props.windSpeed * 10) / 10;
  const windSpeedDisplay = `${roundedWindSpeed} m/s`;

  // 5. Process forecast data
  const processedForecast: ProcessedForecastDay[] = (props.forecast || []).map((forecastDay) => {
    // Infer condition category from icon emoji
    const styleCategory = emojiToCondition(forecastDay.icon);

    return {
      ...forecastDay,
      styleCategory,
    };
  });

  // 6. Return the complete hook result
  return {
    temperatureDisplay,
    conditionCategory,
    humidityDisplay,
    windSpeedDisplay,
    processedForecast,
  };
};


