// components/CurrentWeather.tsx
import { Card, Stack, Text, Heading } from '@ggui-ai/design/primitives';
import type { CurrentWeatherProps } from './types';

/**
 * CurrentWeather Component
 * Displays the current weather conditions prominently:
 * - City name
 * - Large temperature reading with unit
 * - Weather condition text
 * - Condition icon/emoji
 */
export function CurrentWeather({
  city,
  temperature,
  unit,
  condition,
  conditionCategory,
}: CurrentWeatherProps): JSX.Element {
  // Map condition category to emoji
  const getConditionEmoji = (category: string): string => {
    switch (category) {
      case 'sunny':
        return '☀️';
      case 'cloudy':
        return '☁️';
      case 'rainy':
        return '🌧️';
      case 'snowy':
        return '❄️';
      case 'stormy':
        return '⛈️';
      case 'foggy':
        return '🌫️';
      default:
        return '🌡️';
    }
  };

  const conditionEmoji = getConditionEmoji(conditionCategory);

  return (
    <Card padding={24} shadow="md" radius="lg">
      <Stack direction="vertical" gap={8}>
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {city}
        </Text>
        <Stack direction="horizontal" gap={16} align="center">
          <Heading level={1}>{temperature}°{unit}</Heading>
          <Text size="4xl">{conditionEmoji}</Text>
        </Stack>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {condition}
        </Text>
      </Stack>
    </Card>
  );
}


