import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import type { WeatherDetailsProps } from '../types';

/**
 * WeatherDetails - Displays humidity and wind speed metrics
 * 
 * Renders humidity percentage and wind speed side-by-side with icons,
 * using semantic design system components for consistent styling.
 */
export const WeatherDetails: React.FC<WeatherDetailsProps> = ({
  humidity,
  windSpeed,
  unit,
}) => {
  // Determine wind unit based on temperature unit context
  // If Celsius/metric, use km/h; if Fahrenheit/imperial, use mph
  const windUnit = unit === 'F' ? 'mph' : 'km/h';

  return (
    <Stack
      direction="horizontal"
      gap={16}
      align="center"
      justify="around"
      style={{
        width: '100%',
      }}
    >
      {/* Humidity Metric */}
      <Stack
        direction="vertical"
        align="center"
        gap={4}
      >
        <Text
          variant="body"
          size="2xl"
          style={{
            lineHeight: '1',
          }}
        >
          💧
        </Text>
        <Text
          variant="bodyLarge"
          weight="semibold"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {humidity}%
        </Text>
        <Text
          variant="label"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          Humidity
        </Text>
      </Stack>

      {/* Wind Speed Metric */}
      <Stack
        direction="vertical"
        align="center"
        gap={4}
      >
        <Text
          variant="body"
          size="2xl"
          style={{
            lineHeight: '1',
          }}
        >
          💨
        </Text>
        <Text
          variant="bodyLarge"
          weight="semibold"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {windSpeed} {windUnit}
        </Text>
        <Text
          variant="label"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          Wind Speed
        </Text>
      </Stack>
    </Stack>
  );
};

