// components/ForecastStrip.tsx
import { Stack, Divider } from '@ggui-ai/design/primitives';
import ForecastCard from './ForecastCard';
import type { ForecastStripProps } from '../types';

/**
 * ForecastStrip Component
 *
 * Renders a horizontal, scrollable container displaying a 5-day weather forecast.
 * Each day is represented by a ForecastCard component showing the day, icon,
 * high/low temperatures, and styling based on weather condition.
 *
 * Layout:
 * - Horizontal flex row with scrollable overflow on small screens
 * - Responsive card sizing with minimum widths to prevent compression
 * - Visual separator (top border) from parent content
 *
 * Design Tokens:
 * - Uses CSS variables for colors, spacing, and typography
 * - Follows GGUI design system conventions
 *
 * Props:
 * - forecast: Array of ProcessedForecastDay objects (includes styleCategory)
 * - unit: Temperature unit string ("C", "F", etc.)
 *
 * Renders:
 * - Optional top divider for visual separation
 * - Horizontal Stack with padding and scrollable overflow
 * - ForecastCard for each day in the forecast array
 */
export default function ForecastStrip({ forecast, unit }: ForecastStripProps) {
  return (
    <>
      {/* Top divider to separate forecast from current weather section */}
      <Divider orientation="horizontal" margin={0} />

      {/* Horizontal scrollable container for forecast cards */}
      <div
        style={{
          display: 'flex',
          flexDirection: 'row',
          gap: 'var(--ggui-spacing-2, 8px)',
          padding: 'var(--ggui-spacing-4, 16px)',
          overflowX: 'auto',
          overflowY: 'hidden',
          width: '100%',
          minHeight: '140px', // Accommodate card content + padding
          scrollBehavior: 'smooth',
          WebkitOverflowScrolling: 'touch', // Smooth scroll on iOS
        }}
      >
        {/* Render each forecast day as a ForecastCard */}
        {forecast.map((day, index) => (
          <ForecastCard
            key={`${day.day}-${index}`}
            day={day.day}
            icon={day.icon}
            high={day.high}
            low={day.low}
            unit={unit}
            styleCategory={day.styleCategory}
          />
        ))}
      </div>
    </>
  );
}


