// components/ForecastCard.tsx
import React from 'react';
import { Card, Stack, Text, Spacer } from '@ggui-ai/design/primitives';
import type { ForecastCardProps } from './types';

/**
 * ForecastCard Component
 * 
 * Renders a single day's forecast information in a compact card layout.
 * Displays day abbreviation, weather icon, and high/low temperatures.
 * Designed to be used within a horizontal scrollable forecast strip.
 */
export function ForecastCard({
  day,
  icon,
  high,
  low,
  unit,
  styleCategory,
}: ForecastCardProps): React.ReactElement {
  return (
    <Card
      padding={`var(--ggui-spacing-2, 8px)`}
      shadow="sm"
      border={true}
      radius="md"
      style={{
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        minWidth: '80px',
        transition: 'background-color 200ms ease-in-out, box-shadow 200ms ease-in-out',
      }}
    >
      <Stack
        direction="vertical"
        gap={`var(--ggui-spacing-2, 8px)`}
        align="center"
      >
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {day}
        </Text>

        <Text size="2xl" weight="bold" align="center">
          {icon}
        </Text>

        <Spacer size={4} />

        <Stack direction="horizontal" gap={`var(--ggui-spacing-1, 4px)`} align="center" justify="center">
          <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            {high}°{unit}
          </Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {low}°{unit}
          </Text>
        </Stack>
      </Stack>
    </Card>
  );
}


