import React from 'react';
import { Container, Card, Stack, Divider, Text, Heading } from '@ggui-ai/design/primitives';
import { useComponent } from './hooks';
import { CurrentWeather } from './components/CurrentWeather';
import { WeatherDetails } from './components/WeatherDetails';
import { ForecastStrip } from './components/ForecastStrip';
import type { Props } from './types';

export const Component: React.FC<Props> = (props) => {
  const {
    temperatureDisplay,
    conditionCategory,
    humidityDisplay,
    windSpeedDisplay,
    processedForecast,
  } = useComponent(props);

  const unit = props.unit || 'C';

  return (
    <Container
      maxWidth="md"
      center
      padding="var(--ggui-spacing-2, 8px)"
      style={{
        '@media (min-width: 640px)': {
          padding: 'var(--ggui-spacing-4, 16px)',
        },
      }}
    >
      <Card
        padding="var(--ggui-spacing-4, 16px)"
        shadow="md"
        radius="lg"
        border={true}
        style={{
          '@media (min-width: 768px)': {
            padding: 'var(--ggui-spacing-6, 24px)',
          },
        }}
      >
        <Stack
          direction="vertical"
          gap="var(--ggui-spacing-4, 16px)"
          align="stretch"
        >
          {/* Section 1: Current Weather */}
          <CurrentWeather
            city={props.city}
            temperature={props.temperature}
            unit={unit}
            condition={props.condition}
            conditionCategory={conditionCategory}
          />

          {/* Divider */}
          <Divider
            orientation="horizontal"
            margin="var(--ggui-spacing-2, 8px)"
            color="var(--ggui-color-outline, #d4d4d8)"
          />

          {/* Section 2: Weather Details (Humidity & Wind) */}
          <WeatherDetails
            humidity={props.humidity}
            windSpeed={props.windSpeed}
            unit={unit}
          />

          {/* Divider */}
          <Divider
            orientation="horizontal"
            margin="var(--ggui-spacing-2, 8px)"
            color="var(--ggui-color-outline, #d4d4d8)"
          />

          {/* Section 3: 5-Day Forecast Strip */}
          <ForecastStrip
            forecast={processedForecast}
            unit={unit}
          />
        </Stack>
      </Card>
    </Container>
  );
};

